from Crypto.Util.number import getPrime, bytes_to_long

p = getPrime(1024)
q = getPrime(1024)

N = (p**2) * q
e = 65537

flag = b"grey{fake_flag_for_testing}"
m = bytes_to_long(flag)
c = pow(m, e, N)

p_msb = (p >> 320) << 320

print(f"{N = }")
print(f"{e = }")
print(f"{c = }")
print(f"{p_msb = }")

